SET statement_timeout = 0;
SET lock_timeout = 0;
SET idle_in_transaction_session_timeout = 0;
SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SET client_min_messages = warning;
SET row_security = off;
DROP TABLE IF EXISTS public.cons_mat, public.cons_proc, public.consulta, public.material, public.procedimento, public.paciente, public.dentista, public.usuario CASCADE;
CREATE TABLE public.dentista (den_id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, den_nome character varying(50) NOT NULL, den_cro numeric(5,0) NOT NULL, den_fone character varying(14), den_email character varying(100));
CREATE TABLE public.paciente (pac_id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, pac_cpf character varying(14), pac_nome character varying(50) NOT NULL, pac_cep character varying(9), pac_rua character varying(50), pac_numero character varying(10), pac_bairro character varying(30), pac_cidade character varying(20), pac_uf character varying(2), pac_fone character varying(14), pac_email character varying(100), pac_histo text);
CREATE TABLE public.material (mat_id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, mat_desc character varying(40) NOT NULL, mat_preco numeric(9,2));
CREATE TABLE public.procedimento (pro_id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, pro_desc character varying(40) NOT NULL, pro_tempo numeric(2,0), pro_valor numeric(9,2));
CREATE TABLE public.usuario (uso_id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, uso_nome character varying(20) NOT NULL, uso_nivel numeric(1,0) NOT NULL, uso_senha character varying(20) NOT NULL);
CREATE TABLE public.consulta (con_id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, con_relato text, con_data date NOT NULL, con_horario numeric(2,0) NOT NULL, pac_id integer REFERENCES public.paciente(pac_id), den_id integer REFERENCES public.dentista(den_id), con_efetivado boolean DEFAULT false);
CREATE TABLE public.cons_mat (cm_id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, mat_id integer REFERENCES public.material(mat_id), con_id integer REFERENCES public.consulta(con_id), cm_quant numeric(2,0));
CREATE TABLE public.cons_proc (cp_is integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, con_id integer REFERENCES public.consulta(con_id), pro_id integer REFERENCES public.procedimento(pro_id), cp_quant numeric(2,0));
